    except Exception:
        # try truncate
        try:
            cd = datetime.fromisoformat(cd_str)
        except Exception:
            continue
    # consider date only
    if cd.date() >= start.date() and cd.date() <= end.date():
        aid = c.get('accountid')
        if aid:
            matched_accounts.add(aid.strip())
